#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int X;
        scanf("%d", &X);
        int n = (int)sqrt(2*X);
        while (n*(n+1)/2 < X) n++;
        while (n*(n+1)/2 > X) n--;
        int ans = n + X - n*(n+1)/2;
        printf("%d\n", ans);
    }
    return 0;
}

