code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int X = sc.nextInt();
            int n = (int)Math.sqrt(2*X);
            while (n*(n+1)/2 < X) n++;
            while (n*(n+1)/2 > X) n--;
            int ans = n + X - n*(n+1)/2;
            System.out.println(ans);
        }
    }
}

